"""Панель выбора сигнала."""from __future__ import annotationsfrom typing import Anyfrom PySide6.QtWidgets import QComboBox, QGroupBox, QLabel, QVBoxLayout, QWidgetfrom ...core.registry import Registryfrom .params_editor import ParamsEditorclass SignalPanel(QGroupBox):    def __init__(self, registry: Registry, parent: QWidget | None = None) -> None:        super().__init__("Сигнал", parent)        self._registry = registry        self._combo = QComboBox()        self._combo.addItems(registry.list_signals())        self._editor = ParamsEditor()        lay = QVBoxLayout(self)        lay.addWidget(QLabel("Тип сигнала:"))        lay.addWidget(self._combo)        lay.addWidget(self._editor)        self._combo.currentTextChanged.connect(self._on_selection_changed)        self._on_selection_changed(self._combo.currentText())    def selected_name(self) -> str:        return self._combo.currentText()    def params(self) -> dict[str, Any]:        return self._editor.values()    def _on_selection_changed(self, name: str) -> None:        if not name:            return        impl = self._registry.get_signal(name)        self._editor.set_schema(impl.params_schema)